import time
from pathlib import Path
from typing import List, Callable, Dict


class FileWatcher:
    def __init__(self, files: List[Path], callback: Callable[[List[Path]], None], interval: float = 1.0):
        self.files = files
        self.callback = callback
        self.interval = interval
        self._mtimes: Dict[Path, float] = {}
        self._running = False

    def _get_mtimes(self) -> Dict[Path, float]:
        mtimes = {}
        for f in self.files:
            if f.exists():
                mtimes[f] = f.stat().st_mtime
        return mtimes

    def _check_changes(self) -> List[Path]:
        current = self._get_mtimes()
        changed = []
        for f, mtime in current.items():
            if f not in self._mtimes or self._mtimes[f] != mtime:
                changed.append(f)
        self._mtimes = current
        return changed

    def start(self):
        self._mtimes = self._get_mtimes()
        self._running = True
        # Initial run
        self.callback(self.files)
        while self._running:
            time.sleep(self.interval)
            changed = self._check_changes()
            if changed:
                print(f'\n--- Files changed: {", ".join(str(f) for f in changed)} ---')
                self.callback(changed)

    def stop(self):
        self._running = False
